@Singleton
class ApplicationScope @Inject constructor(
    @ApplicationDispatcher dispatcher: CoroutineDispatcher
) : Closeable {
    private val job = SupervisorJob()
    val scope = CoroutineScope(job + dispatcher + CoroutineName("AppScope"))

    override fun close() { job.cancel() }
}

suspend fun loadJobScreen(jobId: String): JobScreen = coroutineScope {
    val job = async { jobRepository.getJob(jobId) }
    val saved = async { savedRepository.isSaved(jobId) }
    JobScreen(job.await(), saved.await())
}

suspend fun saveProfile(profile: Profile) {
    CoroutineScope(Dispatchers.IO).launch {
        api.save(profile)
    }
    // Hàm trả về dù save chưa xong; caller không cancel/chờ/biết lỗi.
}

class SyncCoordinator(
    private val appScope: CoroutineScope,
    private val repository: SyncRepository
) {
    fun start(): Job = appScope.launch { repository.syncUntilCancelled() }
}

suspend fun loadHome(userId: String): HomeResult = supervisorScope {
    val profile = async { profileRepository.get(userId) }
    val recommendations = async { runCatchingCancellable { jobRepository.recommended(userId) } }
    val unread = async { runCatchingCancellable { chatRepository.unreadCount(userId) } }

    HomeResult(
        profile = profile.await(),
        recommendations = recommendations.await(),
        unread = unread.await()
    )
}

suspend inline fun <T> runCatchingCancellable(
    crossinline block: suspend () -> T
): Result<T> = try {
    Result.success(block())
} catch (cancelled: CancellationException) {
    throw cancelled
} catch (error: Throwable) {
    Result.failure(error)
}

class SessionScopeFactory(
    private val dispatcher: CoroutineDispatcher
) {
    fun create(userId: String): SessionScope {
        val job = SupervisorJob()
        return SessionScope(
            userId = userId,
            scope = CoroutineScope(job + dispatcher + CoroutineName("Session-$userId")),
            cancel = { job.cancel() }
        )
    }
}

data class SessionScope(
    val userId: String,
    val scope: CoroutineScope,
    val cancel: () -> Unit
)

suspend fun index(items: List<Item>): Index = withContext(Dispatchers.Default) {
    val builder = IndexBuilder()
    items.forEachIndexed { index, item ->
        if (index % 100 == 0) ensureActive()
        builder.add(item)
    }
    builder.build()
}
